			ai_multi_send_robot_position(objnum, -1);

		do_firing_stuff(obj, player_visibility, &vec_to_player);
	}
	break;
}

case AIM_RUN_FROM_OBJECT:
	compute_vis_and_vec(obj, &vis_vec_pos, ailp, &vec_to_player, &player_visibility, robptr, &visibility_and_vec_computed);

	if (player_visibility) {
		if (ailp->player_awareness_type == 0)
			ailp->player_awareness_type = PA_WEAPON_ROBOT_COLLISION;

	}

	//	If in multiplayer, only do if player visible.  If not multiplayer, do always.
	if (!(Game_mode & GM_MULTI) || player_visibility)
		if (ai_multiplayer_awareness(obj, 75)) {
			ai_follow_path(obj, player_visibility, previous_visibility, &vec_to_player);
			ai_multi_send_robot_position(objnum, -1);
		}

	if (aip->GOAL_STATE != AIS_FLIN)
		aip->GOAL_STATE = AIS_LOCK;
	else if (aip->CURRENT_STATE == AIS_FLIN)
		aip->GOAL_STATE = AIS_LOCK;

	//	Bad to let run_from robot fire at player because it will cause a war in which it turns towards the
	//	player to fire and then towards its goal to move.
	// do_firing_stuff(obj, player_visibility, &vec_to_player);
	//	Instead, do this:
	//	(Note, only drop if player is visible.  This prevents the bombs from being a giveaway, and
	//	also ensures that the robot is moving while it is dropping.  Also means fewer will be dropped.)
	if ((ailp->next_fire <= 0) && (player_visibility))
	{
		vms_vector	fire_vec, fire_pos;

		if (!ai_multiplayer_awareness(obj, 75))
			return;

		fire_vec = obj->orient.fvec;
		vm_vec_negate(&fire_vec);
		vm_vec_add(&fire_pos, &obj->pos, &fire_vec);

		if (aip->SUB_FLAGS & SUB_FLAGS_SPROX)
			Laser_create_new_easy(&fire_vec, &fire_pos, obj - Objects, ROBOT_SUPERPROX_ID, 1);
		else
			Laser_create_new_easy(&fire_vec, &fire_pos, obj - Objects, PROXIMITY_ID, 1);

      if not ok then raise Early_return;
      unpack_path_state (Effect.perform (Create_n_segment_path_to_door (8 + difficulty_level, -1)));
      Effect.perform (Ai_multi_send_robot_position (-1))));
(* Phase: D2 specials: snipe, escort, thief *)
if !behavior = aib_snipe
then (
  if obj_ref land 3 = 0 || !previous_visibility <> 0
  then (
    compute_vis ();
    (* If sniper is in still mode, switch to snipe mode if visible or hit *)
    if !mode = aim_still then
      (if !player_visibility <> 0
          || !player_awareness_type = pa_weapon_robot_collision
       then mode := aim_snipe_attack);
    if thief = 0 && !mode <> aim_still then (
      (* Ported do_snipe_frame: handle snipe mode transitions and timing *)
      if !dist_to_player <= f1_0 * 500 then (
        let vtpx, vtpy, vtpz = !vec_to_player in
        (match !mode with
         | m when m = aim_snipe_wait ->
           if not (!dist_to_player > f1_0 * 50 && !next_action_time > 0) then (
             next_action_time := snipe_wait_time;
             (* NOTE: find_connected_distance not available as effect;
                always attempt path creation. Divergence expected until
                find_connected_distance is available in ai_frame context. *)
             unpack_path_state (Effect.perform (Create_path_to_player (30, 1)));
             mode := aim_snipe_attack;
             next_action_time := snipe_attack_time)
         | m when m = aim_snipe_retreat || m = aim_snipe_retreat_backwards ->
           if !next_action_time < 0 then (
             mode := aim_snipe_wait;
             next_action_time := snipe_wait_time)
           else if !player_visibility = 0 || !next_action_time > snipe_abort_retreat_time then (
             unpack_path_state (Effect.perform
               (Ai_follow_path (!player_visibility, !player_visibility, vtpx, vtpy, vtpz)));
             mode := aim_snipe_retreat_backwards)
           else (
             mode := aim_snipe_fire;
             next_action_time := snipe_fire_time / 2)
         | m when m = aim_snipe_attack ->
           if !next_action_time < 0 then (
             mode := aim_snipe_retreat;
             next_action_time := snipe_wait_time)
           else (
             unpack_path_state (Effect.perform
               (Ai_follow_path (!player_visibility, !player_visibility, vtpx, vtpy, vtpz)));
             if !player_visibility <> 0 then (
               mode := aim_snipe_fire;
               next_action_time := snipe_fire_time)
             else
               mode := aim_snipe_attack)
         | m when m = aim_snipe_fire ->
           if !next_action_time < 0 then (
             let pr = Effect.perform P_Rand in
             unpack_path_state (Effect.perform
               (Create_n_segment_path (10 + pr / 2048, console_segnum)));
             (* NOTE: polish_path not available as effect; path used unpolished.
                Divergence expected until polish_path is ported. *)
             let pr2 = Effect.perform P_Rand in
             if pr2 < 8192
             then mode := aim_snipe_retreat_backwards
             else mode := aim_snipe_retreat;
             next_action_time := snipe_retreat_time)
         | _ ->
           mode := aim_snipe_attack;
           next_action_time := f1_0))))
  else if thief = 0 && companion = 0
  then (early_return_flag := 1; raise Early_return))
else if companion <> 0
then (
  compute_vis ();
  unpack_path_state (Effect.perform (Do_escort_frame (!dist_to_player, !player_visibility)));
  (* Companion extras: danger laser evasion + flare firing (C lines 1433-1466) *)
  let vtpx, vtpy, vtpz = !vec_to_player in
  let new_nf = Effect.perform
    (Do_companion_extras (!dist_to_player, !player_visibility, vtpx, vtpy, vtpz, !mode, !next_fire, !next_fire2)) in
  next_fire := new_nf);
(* Thief section: runs independently of snipe (thief has AIB_SNIPE behavior) *)
if thief <> 0
then (
  compute_vis ();
  (* Ported do_thief_frame: handle thief mode transitions and timing.
     NOTE: init_thief_for_level (negative levels only) not ported.
     NOTE: find_connected_distance not available; always attempt path creation.
     NOTE: move_towards_player/ai_turn_towards_vector not available as effects;
           thief physical movement in attack mode will diverge. *)
  let thief_done = ref false in
  let thief_wait_time = thief_wait_times.(difficulty_level) in
  (* C line 1352: early return if far and timer positive *)
  if !dist_to_player > f1_0 * 500 && !next_action_time > 0 then
    thief_done := true;
  if not !thief_done then (
    (* C line 1355: if player dead, retreat *)
    if player_is_dead <> 0 then
      mode := aim_thief_retreat;
    (match !mode with
     | m when m = aim_thief_wait ->
       (* C lines 1362-1376: awareness/visibility checks with early returns *)
       if !player_awareness_type >= pa_player_collision then (
         player_awareness_type := 0;
         unpack_path_state (Effect.perform (Create_path_to_player (30, 1)));
         mode := aim_thief_attack;
         next_action_time := thief_attack_time / 2;
         thief_done := true)
       else if !player_visibility <> 0 then (
         unpack_path_state (Effect.perform (Create_n_segment_path (15, console_segnum)));
         mode := aim_thief_retreat;
         thief_done := true);
       (* C lines 1378-1389: distance/timer gate, then path to player *)
       if not !thief_done then (
         if not (!dist_to_player > f1_0 * 50 && !next_action_time > 0) then (
           next_action_time := thief_wait_time / 2;
           (* NOTE: find_connected_distance not available; always create path *)
           unpack_path_state (Effect.perform (Create_path_to_player (30, 1)));
           mode := aim_thief_attack;
           next_action_time := thief_attack_time))
     | m when m = aim_thief_retreat ->
       (* C lines 1396-1424 *)
       if !next_action_time < 0 then (
         mode := aim_thief_wait;
         next_action_time := thief_wait_time)
       else if !dist_to_player < f1_0 * 100
               || !player_visibility <> 0
               || !player_awareness_type >= pa_player_collision then (
         let vtpx, vtpy, vtpz = !vec_to_player in
         unpack_path_state (Effect.perform
           (Ai_follow_path (!player_visibility, !player_visibility, vtpx, vtpy, vtpz)));
         if !dist_to_player < f1_0 * 100
            || !player_awareness_type >= pa_player_collision then (
           (* C lines 1403-1420: path end check + new retreat path.
              NOTE: path_dir not tracked in OCaml; path end check simplified.
              NOTE: shield-based path lengthening skipped (shields not available). *)
           if (!cur_path_index <= 1 || !cur_path_index >= !path_length - 1) then (
             player_awareness_type := 0;
             unpack_path_state (Effect.perform (Create_n_segment_path (10, console_segnum)));
             mode := aim_thief_retreat))
         else
           mode := aim_thief_retreat)
     | m when m = aim_thief_attack ->
       (* C lines 1434-1470 *)
       if !player_awareness_type >= pa_player_collision then (
         player_awareness_type := 0;
         let pr = Effect.perform P_Rand in
         if pr > 8192 then (
           unpack_path_state (Effect.perform (Create_n_segment_path (10, console_segnum)));
           next_action_time := thief_wait_time / 2;
           mode := aim_thief_retreat))
       else if !next_action_time < 0 then (
         next_action_time := f1_0;
         unpack_path_state (Effect.perform (Create_path_to_player (100, 0)));
         mode := aim_thief_attack)
       else (
         if !player_visibility <> 0 && !dist_to_player < f1_0 * 100 then (
           (* NOTE: ai_turn_towards_vector and move_towards_player not available
              as effects. Physical movement divergence expected.
              NOTE: player-looking dot check skipped (ConsoleObject orient.fvec
              not available). *)
           ())
         else (
           if !path_length > 1 || frame_count land 0x0f = 0 then (
             let vtpx, vtpy, vtpz = !vec_to_player in
             unpack_path_state (Effect.perform
               (Ai_follow_path (!player_visibility, !player_visibility, vtpx, vtpy, vtpz)));
             mode := aim_thief_attack)))
     | _ ->
       mode := aim_thief_attack;
       next_action_time := f1_0));
  (* Thief extras: flare firing (C lines 1478-1494) *)
  let vtpx, vtpy, vtpz = !vec_to_player in
  let new_nf = Effect.perform
    (Do_thief_extras (!dist_to_player, !player_visibility, vtpx, vtpy, vtpz, !next_fire, !next_fire2)) in
  next_fire := new_nf);
(* Phase: mode dispatch (D2) *)
(match !mode with
 | m when m = aim_chase_object ->
   let circle_distance = circle_distance_diff + console_size in
   let circle_distance =
     if attack_type <> 1
     then circle_distance + ((objnum land 0xf) * f1_0 / 2)
     else circle_distance
   in
   compute_vis ();
   let chase_break = ref false in
   if !player_visibility < 2 && !previous_visibility = 2
